(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[3246],{22248:function(e,s,t){Promise.resolve().then(t.bind(t,13015))},13015:function(e,s,t){"use strict";t.r(s),t.d(s,{default:function(){return a}});var i=t(57437),r=t(2265);let n=[{id:"nature",title:"Nature du Protocole",content:["AVERTISSEMENT : KAL est un protocole de finance d\xe9centralis\xe9e (DeFi) exp\xe9rimental fonctionnant sur la blockchain Arbitrum (r\xe9seau de couche 2 d\xe9velopp\xe9 par Offchain Labs). Il ne constitue en aucun cas un produit financier r\xe9glement\xe9, un fonds de placement, un service de gestion de portefeuille, ou un conseil en placement.","KAL est un protocole logiciel d\xe9centralis\xe9 compos\xe9 de 24 contrats intelligents autonomes d\xe9ploy\xe9s sur la blockchain Arbitrum. Les utilisateurs interagissent directement avec ces contrats. Aucun interm\xe9diaire humain ne g\xe8re, contr\xf4le ou a acc\xe8s aux fonds d\xe9pos\xe9s.","Le protocole comprend : 5 strat\xe9gies de trading algorithmique (HORIZON, VALKYRIE, REVOLUTION, TREASURY, ORION), 3 pools de liquidit\xe9 (KAL/USDC, KAL/WETH, USDC/WETH), un syst\xe8me d'\xe9change d\xe9centralis\xe9 (KalSwap), un m\xe9canisme de pr\xe9vente en 3 rounds, et un syst\xe8me de mise en jeu (staking) KAL.","Les performances historiques affich\xe9es proviennent de tests historiques algorithmiques sur donn\xe9es pass\xe9es. Elles ne constituent en aucun cas une promesse, une garantie ou une pr\xe9diction de performances futures. Vous pouvez perdre la totalit\xe9 des fonds d\xe9pos\xe9s.","Protections int\xe9gr\xe9es : KalTimelock (d\xe9lai obligatoire sur les op\xe9rations admin), anti-rug pull (limite de retrait de liquidit\xe9 de 25% par 24h), suppression de la fonction d'extraction d'urgence, protection anti-slippage configurable, et code source v\xe9rifiable sur Arbiscan.","En utilisant ce protocole, vous reconnaissez que : (1) vous comprenez les risques li\xe9s \xe0 la DeFi et aux crypto-actifs, (2) vous n'utilisez que des fonds dont la perte totale n'affecterait pas votre situation financi\xe8re, (3) vous \xeates seul responsable de vos d\xe9cisions, (4) aucune entit\xe9 ne vous a promis de performance ou de r\xe9sultat."]},{id:"conditions",title:"Conditions G\xe9n\xe9rales d'Utilisation",content:["Derni\xe8re mise \xe0 jour : Mars 2026","Article 1 — Objet. Les pr\xe9sentes conditions g\xe9n\xe9rales d'utilisation (CGU) r\xe9gissent l'acc\xe8s et l'utilisation du protocole KAL, accessible via app.kalmydas.com, kalmydas.com, docs.kalmydas.com et api.kalmydas.com (ci-apr\xe8s \"la Plateforme\"). En acc\xe9dant \xe0 la Plateforme ou en interagissant avec les contrats intelligents du protocole KAL, vous acceptez l'int\xe9gralit\xe9 des pr\xe9sentes CGU.",'Article 2 — D\xe9finitions. "Protocole" : ensemble des contrats intelligents d\xe9ploy\xe9s sur Arbitrum. "KAL" : jeton utilitaire ERC-20 du Protocole (pas une valeur mobili\xe8re). "Jetons LP" : tokens repr\xe9sentant une part dans une pool de liquidit\xe9. "Pass d\'acc\xe8s" : NFT Soulbound requis pour acc\xe9der aux pools de trading.',"Article 3 — \xc9ligibilit\xe9. L'utilisateur doit \xeatre \xe2g\xe9 d'au moins 18 ans, ne pas r\xe9sider dans un pays soumis \xe0 des sanctions internationales, ne pas figurer sur une liste de sanctions (OFAC, ONU, UE), et avoir la capacit\xe9 juridique de conclure un contrat.","Article 4 — Nature du Protocole. KAL n'est PAS un produit d'investissement, un service de gestion de portefeuille, un conseil en investissement, un interm\xe9diaire financier, un d\xe9positaire, une banque, un produit financier r\xe9glement\xe9, ni une offre de valeurs mobili\xe8res. KAL EST un ensemble de contrats intelligents autonomes, un logiciel open-source v\xe9rifiable sur Arbiscan, et un protocole DeFi exp\xe9rimental.","Article 5 — Pass d'acc\xe8s. L'acc\xe8s aux strat\xe9gies de trading n\xe9cessite un Pass d'acc\xe8s NFT valide. Le co\xfbt est de 1 USDC par jour, avec des dur\xe9es de 1, 7, 30, 90, 180 ou 365 jours. Le Pass est un jeton ERC-721 non transf\xe9rable (Soulbound). Le solde non consomm\xe9 peut \xeatre r\xe9cup\xe9r\xe9 via d\xe9sactivation.","Article 6 — Liquidit\xe9. L'utilisateur peut fournir de la liquidit\xe9 dans 3 pools AMM : KAL/USDC (poids : 50% des r\xe9compenses), KAL/WETH (30%), USDC/WETH (20%). Les poids sont fixes et immutables dans le contrat LiquidityRewardsV6. Fournir de la liquidit\xe9 expose au risque de perte impermanente.","Article 7 — \xc9change (Swap). Les AMMs (KalSwap, KalSwapETH, KalSwapKALETH) pr\xe9l\xe8vent 0.3% par \xe9change. Une protection anti-rug limite les retraits de liquidit\xe9 \xe0 25% par tranche de 24 heures.","Article 8 — Pr\xe9vente. 3 rounds \xe0 prix croissant ($0.05, $0.10, $0.20 par KAL). R\xe9partition : 60% auto-stak\xe9s en jetons LP + 40% KAL directs. Maximum $5 000 par personne. Aucun remboursement apr\xe8s contribution.","Article 9 — Responsabilit\xe9s de l'utilisateur. L'utilisateur est seul responsable de la s\xe9curit\xe9 de son portefeuille num\xe9rique, de ses cl\xe9s priv\xe9es, et de ses identifiants de connexion. La perte d'acc\xe8s au portefeuille entra\xeene la perte d\xe9finitive des fonds.",'Article 10 — Limitation de responsabilit\xe9. La Plateforme est fournie "en l\'\xe9tat" (as is), sans aucune garantie. Le Protocole ne peut \xeatre tenu responsable de toute perte de fonds, interruption de service, erreur de donn\xe9es, vuln\xe9rabilit\xe9, acc\xe8s non autoris\xe9, ou cons\xe9quence de modifications r\xe9glementaires.',"Article 11 — Donn\xe9es personnelles. Le Protocole ne collecte aucune donn\xe9e personnelle identifiable. Les transactions sur la blockchain sont publiques par nature. La connexion via Privy peut impliquer la collecte de donn\xe9es par Privy selon ses propres conditions.",'Article 12 — Propri\xe9t\xe9 intellectuelle. Le nom "KAL", le nom "KalMydas", les logos, le code source des contrats intelligents, et le contenu du Protocole sont la propri\xe9t\xe9 de KalMydas. Toute reproduction non autoris\xe9e est interdite.',"Article 13 — Modification des CGU. Les pr\xe9sentes CGU peuvent \xeatre modifi\xe9es \xe0 tout moment. Les modifications entrent en vigueur d\xe8s leur publication. L'utilisation continue vaut acceptation.","Article 14 — Juridiction. Les CGU sont soumises au droit applicable dans la juridiction de l'utilisateur. En cas de litige, les parties s'engagent \xe0 rechercher une r\xe9solution amiable avant toute proc\xe9dure judiciaire."]},{id:"risques",title:"Avertissement sur les Risques",content:["AVERTISSEMENT IMPORTANT : Utiliser le protocole KAL comporte des risques significatifs. Les performances pass\xe9es ne garantissent pas les r\xe9sultats futurs. Vous pouvez perdre la totalit\xe9 de vos fonds.","Risque de march\xe9. Le march\xe9 de l'or (XAUUSD) est volatile. Les algorithmes de trading peuvent subir des pertes importantes, y compris des pertes maximales d\xe9passant 50% des fonds dans certains cas (notamment les strat\xe9gies TREASURY et ORION). Les conditions de march\xe9 extr\xeames peuvent g\xe9n\xe9rer des pertes rapides et significatives.","Risque de perte totale. Il est possible de perdre l'int\xe9gralit\xe9 des fonds d\xe9pos\xe9s. Cela est particuli\xe8rement vrai pour les strat\xe9gies \xe0 profil agressif. N'utilisez que des fonds dont la perte totale n'affecterait pas votre situation financi\xe8re.","Risque algorithmique. Les algorithmes sont optimis\xe9s sur des donn\xe9es historiques (tests historiques). Les performances pass\xe9es ne sont pas indicatives des performances futures. Les algorithmes peuvent ne pas s'adapter correctement \xe0 de nouvelles conditions de march\xe9.","Risque de contrat intelligent. Les 24 contrats intelligents du Protocole peuvent contenir des vuln\xe9rabilit\xe9s ou des bugs, malgr\xe9 l'audit de s\xe9curit\xe9 complet (priorit\xe9s P1/P2/P3 valid\xe9es) et les 171 tests unitaires. Les interactions entre contrats \xe9largissent la surface d'attaque.","Risque DeFi et technique. La finance d\xe9centralis\xe9e comporte des risques inh\xe9rents : bugs de protocole, attaques de type pr\xeat \xe9clair, manipulations de prix (oracle), et indisponibilit\xe9 temporaire du r\xe9seau.","Risque de liquidit\xe9. La liquidit\xe9 du jeton KAL et des pools peut \xeatre limit\xe9e, entra\xeenant des difficult\xe9s \xe0 retirer des fonds importants rapidement. La courbe de valorisation (premium 2x-10x) peut amplifier les pertes.","Risque de perte impermanente. Fournir de la liquidit\xe9 dans les 3 pools AMM (KAL/USDC, KAL/WETH, USDC/WETH) expose au risque de perte impermanente. Cette perte peut \xeatre permanente en cas de retrait d\xe9favorable. Les r\xe9compenses KAL ne compensent pas n\xe9cessairement cette perte.","Risque r\xe9glementaire. La r\xe9glementation des actifs num\xe9riques \xe9volue rapidement. Des changements pourraient restreindre ou interdire l'acc\xe8s au Protocole dans certaines juridictions.","Risque d'infrastructure et d'ex\xe9cution. Le lien entre les algorithmes et les contrats intelligents passe par un script op\xe9rateur centralis\xe9 (bot-operator). Une panne ou indisponibilit\xe9 peut entra\xeener un d\xe9calage entre l'ex\xe9cution r\xe9elle et le report on-chain.","Risque oracle et donn\xe9es de prix. Les donn\xe9es de prix proviennent de sources tierces (Chainlink ETH/USD pour les pools ETH). Une erreur ou des donn\xe9es erron\xe9es peuvent affecter les \xe9changes et valorisations.","Risque de d\xe9pendance \xe0 Arbitrum. Arbitrum est un rollup optimistic avec un s\xe9quenceur centralis\xe9. Des indisponibilit\xe9s temporaires sont possibles. Les retraits vers L1 Ethereum sont soumis \xe0 un d\xe9lai d'environ 7 jours.","Risque MEV et devancement de transaction. Bien que le s\xe9quenceur FIFO d'Arbitrum r\xe9duise significativement les risques de MEV, des transactions importantes peuvent th\xe9oriquement \xeatre exploit\xe9es par des tiers.","Risque de personne cl\xe9. Le d\xe9veloppement et l'administration du protocole reposent sur un nombre limit\xe9 de personnes. Le KalTimelock mitigue partiellement ce risque en imposant un d\xe9lai sur les op\xe9rations administratives.","Risque de compromission d'infrastructure. Les serveurs ex\xe9cutant les scripts op\xe9rateurs pourraient \xeatre compromis. Mitigation : monitoring et alertes Telegram en place.","Risque tokenomics. Les \xe9missions de KAL suivent un mod\xe8le progressif sur 50 ans avec des halvings. Les param\xe8tres peuvent \xeatre ajust\xe9s (ex: r\xe9duction de 50% effectu\xe9e). La valeur du KAL peut fluctuer significativement ou tomber \xe0 z\xe9ro.","Pas de conseil en placement. Le protocole KAL ne fournit aucun conseil en placement, fiscal, ou juridique. Chaque utilisateur est responsable de ses propres d\xe9cisions.","Fiscalit\xe9. Les r\xe9sultats positifs obtenus via le Protocole peuvent \xeatre soumis \xe0 l'imp\xf4t dans le pays de r\xe9sidence de l'utilisateur. L'utilisateur est seul responsable de ses obligations fiscales.","En utilisant le Protocole, vous reconnaissez avoir lu et compris les risques d\xe9crits ci-dessus et acceptez de les assumer enti\xe8rement. Aucune promesse de r\xe9sultat ou de performance n'est faite."]},{id:"frais",title:"Politique de Frais",content:["Derni\xe8re mise \xe0 jour : Mars 2026. KAL Platform applique une structure de frais transparente et comp\xe9titive, enti\xe8rement inscrite dans les contrats intelligents.","Frais de gestion : 0% sur les d\xe9p\xf4ts. Aucun frais n'est pr\xe9lev\xe9 sur les fonds d\xe9pos\xe9s dans les pools de trading. Exception : les strat\xe9gies REVOLUTION et TREASURY appliquent des frais de gestion de 3% par an.","Frais de performance. Les frais de performance sont pr\xe9lev\xe9s uniquement sur les r\xe9sultats positifs r\xe9alis\xe9s, selon le principe du Plus-haut historique (HWM). Ce m\xe9canisme garantit que les frais ne s'appliquent que sur les nouveaux profits d\xe9passant le plus haut historique du pool.","D\xe9tail des frais par strat\xe9gie : HORIZON (Prudent) — 10% des r\xe9sultats positifs. VALKYRIE (\xc9quilibr\xe9) — 20%. REVOLUTION (Dynamique) — 20% + 3%/an gestion. TREASURY (Agressif) — 20% + 3%/an gestion. ORION (Offensif) — 20%.","Plus-haut historique (HWM). Si un pool subit une perte, aucun frais de performance n'est pr\xe9lev\xe9 tant que le pool n'a pas r\xe9cup\xe9r\xe9 son plus haut niveau pr\xe9c\xe9dent.","Frais de d\xe9p\xf4t et de retrait : 0%. Seuls les frais de r\xe9seau (gas) Arbitrum s'appliquent.","Frais de r\xe9seau. Les transactions sur Arbitrum entra\xeenent des frais de gas tr\xe8s r\xe9duits (quelques centimes). Ces frais sont pay\xe9s au r\xe9seau, pas \xe0 KAL Platform.","Frais d'\xe9change. Les AMMs (KalSwap, KalSwapETH, KalSwapKALETH) pr\xe9l\xe8vent 0.3% par \xe9change. Les \xe9changes via la courbe de valorisation sont soumis \xe0 l'\xe9cart entre prix d'achat et de vente.","Pass d'acc\xe8s. L'acc\xe8s aux strat\xe9gies n\xe9cessite un Pass d'acc\xe8s NFT au co\xfbt de 1 USDC par jour (dur\xe9es : 1, 7, 30, 90, 180 ou 365 jours avec r\xe9ductions 10-30%). Le solde non consomm\xe9 est r\xe9cup\xe9rable via d\xe9sactivation.","R\xe9partition des frais de performance (fee split V7) : 35% r\xe9serve protocole (tr\xe9sorerie et stabilit\xe9), 20% rachat de KAL et recirculation en liquidit\xe9 protocole (POL), 15% r\xe9compenses fournisseurs de liquidit\xe9 (LP), 10% partage de revenus veKAL, 10% fondateur (r\xe9mun\xe9ration op\xe9rationnelle), 5% bonus KAL aux d\xe9posants de strat\xe9gie, 5% tr\xe9sorerie RWA (diversification hors-crypto). Frais de gestion (si applicable) : 50% fondateur, 50% POL. Cette r\xe9partition est inscrite dans le contrat KalFeeSplitV7 et v\xe9rifiable sur Arbiscan.","Pas de frais cach\xe9s. Aucun frais d'inactivit\xe9, de maintenance, de fermeture, ou tout autre frais non mentionn\xe9 ci-dessus. L'int\xe9gralit\xe9 des frais est inscrite dans les contrats intelligents et v\xe9rifiable publiquement."]}];function a(){(0,r.useEffect)(()=>{let e=window.location.hash.replace("#","");e&&setTimeout(()=>{var s;null===(s=document.getElementById(e))||void 0===s||s.scrollIntoView({behavior:"smooth",block:"start"})},100)},[]);let e=e=>{var s;null===(s=document.getElementById(e))||void 0===s||s.scrollIntoView({behavior:"smooth",block:"start"})};return(0,i.jsx)("div",{className:"min-h-screen py-24 px-6",children:(0,i.jsxs)("div",{className:"max-w-4xl mx-auto",children:[(0,i.jsxs)("div",{className:"mb-10",children:[(0,i.jsx)("h1",{className:"text-3xl md:text-4xl font-bold mb-2",children:"Mentions L\xe9gales"}),(0,i.jsx)("p",{className:"text-gray-400",children:"KalMydas — kalmydas.com"})]}),(0,i.jsx)("div",{className:"flex flex-wrap gap-2 mb-8",children:n.map(s=>(0,i.jsx)("button",{onClick:()=>e(s.id),className:"px-4 py-2 rounded-lg text-sm border border-[var(--card-border)] bg-[var(--card-bg)] text-gray-400 hover:text-white hover:border-indigo-500/50 transition",children:s.title},s.id))}),(0,i.jsx)("div",{className:"flex flex-col gap-8",children:n.map(e=>(0,i.jsxs)("section",{id:e.id,className:"rounded-2xl border border-[var(--card-border)] bg-[var(--card-bg)] p-6 md:p-8 scroll-mt-24",children:[(0,i.jsx)("h2",{className:"text-xl md:text-2xl font-bold mb-6 bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent",children:e.title}),(0,i.jsx)("div",{className:"space-y-4 text-gray-300 text-sm md:text-base leading-relaxed",children:e.content.map((e,s)=>(0,i.jsx)("p",{children:e},s))})]},e.id))}),(0,i.jsx)("div",{className:"mt-8 text-center",children:(0,i.jsx)("button",{onClick:()=>window.scrollTo({top:0,behavior:"smooth"}),className:"text-sm text-gray-500 hover:text-indigo-400 transition",children:"Retour en haut ↑"})})]})})}}},function(e){e.O(0,[2971,2117,1744],function(){return e(e.s=22248)}),_N_E=e.O()}]);